#!/usr/bin/env python3
"""Block `pnpm test` (interactive watcher); steer Claude to `pnpm test:ci`."""
import json, sys

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0
    if ev.get("tool_name") != "Bash":
        return 0
    cmd = (ev.get("tool_input") or {}).get("command", "")
    if cmd.strip().startswith("pnpm test") and "test:ci" not in cmd:
        print("Use `pnpm test:ci` instead — `pnpm test` opens an interactive watcher and won't return.", file=sys.stderr)
        return 2
    return 0

if __name__ == "__main__":
    sys.exit(main())

import json, sys, os

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0

    tool = ev.get("tool_name", "")
    inp = ev.get("tool_input") or {}

    if tool != "Read":
        return 0

    file_path = inp.get("file_path", "")
    if not file_path:
        return 0

    basename = os.path.basename(file_path)

    if basename == ".env" or basename.startswith(".env."):
        msg = "BLOCKING: Cannot read {} — secrets stored in .env.local must not be read by Claude.".format(basename)
        print(msg, file=sys.stderr)
        return 2

    return 0

if __name__ == "__main__":
    sys.exit(main())

import json, sys, ast, os

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0

    tool = ev.get("tool_name", "")
    inp = ev.get("tool_input") or {}

    if tool != "Edit":
        return 0

    file_path = inp.get("file_path", "")
    if not file_path.endswith(".py"):
        return 0

    # Only check files we know contain tree-walking code
    if not os.path.exists(file_path):
        return 0

    try:
        with open(file_path) as f:
            tree = ast.parse(f.read())
    except:
        return 0

    # Detect recursive functions in files with tree-walking patterns
    tree_keywords = {"walk", "tree", "traverse", "dfs", "recurse"}
    has_tree_code = False
    recursive_funcs = []

    for node in ast.walk(tree):
        if isinstance(node, ast.FunctionDef):
            func_name = node.name.lower()

            # Check if this file contains tree-walking code
            if any(kw in func_name for kw in tree_keywords):
                has_tree_code = True

            # Check if function is recursive (calls itself)
            for subnode in ast.walk(node):
                if isinstance(subnode, ast.Call):
                    if isinstance(subnode.func, ast.Name) and subnode.func.id == node.name:
                        recursive_funcs.append(node.name)
                        break

    if has_tree_code and recursive_funcs:
        msg = f"REQUIRED FOLLOW-UP: Recursive functions in tree-walking code: {', '.join(set(recursive_funcs))}. Python recursion limit (~1000) causes RecursionError on large trees (2000+ nodes). Use iterative approach with explicit stack worklist instead."
        print(msg, file=sys.stderr)

    return 0

if __name__ == "__main__":
    sys.exit(main())

import json, sys, subprocess, os

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0

    tool = ev.get("tool_name", "")
    inp = ev.get("tool_input") or {}

    # Only check after Edit events on Python files
    if tool != "Edit":
        return 0

    file_path = inp.get("file_path", "")
    if not file_path or not file_path.endswith(".py"):
        return 0

    # Check if file exists and run ruff check
    if not os.path.exists(file_path):
        return 0

    try:
        result = subprocess.run(
            ["ruff", "check", file_path],
            capture_output=True,
            text=True,
            timeout=5
        )
        if result.returncode != 0:
            # Linting errors found
            output = result.stdout or result.stderr
            print(f"REQUIRED FOLLOW-UP: ruff found issues in {file_path}:\n{output}", file=sys.stderr)
            return 2
    except FileNotFoundError:
        # ruff not installed, silently skip
        return 0
    except Exception:
        return 0

    return 0

if __name__ == "__main__":
    sys.exit(main())

import json
import sys
import re
import subprocess
import os

def extract_exports(content):
    """Extract exported identifier names from TypeScript/TSX content."""
    pattern = r'export\s+(?:const|let|var|function|class|interface|type|enum)\s+([A-Za-z_$][A-Za-z0-9_$]*)'
    return set(re.findall(pattern, content))

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0

    tool = ev.get("tool_name", "")
    if tool != "Edit":
        return 0

    inp = ev.get("tool_input") or {}
    file_path = inp.get("file_path", "")

    # Only process TypeScript files
    if not (file_path.endswith(".ts") or file_path.endswith(".tsx")):
        return 0

    # Read the edited file
    try:
        with open(file_path, 'r') as f:
            content = f.read()
    except:
        return 0

    # Extract all exported identifiers
    exports = extract_exports(content)
    if not exports:
        return 0

    # Search for references to each export
    results = []
    for export_name in sorted(exports):
        try:
            result = subprocess.run(
                ["grep", "-r", "--include=*.ts", "--include=*.tsx", "--include=*.js", "--include=*.jsx",
                 "-n", f"\\b{export_name}\\b"],
                capture_output=True,
                text=True,
                timeout=5
            )
            if result.stdout:
                lines = result.stdout.strip().split('\n')
                count = len(lines)
                snippet = '\n    '.join(lines[:3])
                results.append(f"  {export_name}: {count} references\n    {snippet}")
                if count > 3:
                    results.append(f"    ({count - 3} more)")
        except Exception:
            pass

    if results:
        filename = os.path.basename(file_path)
        msg = f"REQUIRED FOLLOW-UP: File {filename} exports identifier(s). Check all references:\n\n"
        msg += "\n".join(results)
        msg += "\n\nDo not stop — verify all references are updated."
        print(msg, file=sys.stderr)

    return 0

if __name__ == "__main__":
    sys.exit(main())

import json
import sys
import re

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0

    tool = ev.get("tool_name", "")
    inp = ev.get("tool_input") or {}

    if tool not in ["Edit", "Write"]:
        return 0

    # Get the content being written
    content = ""
    if tool == "Write":
        content = inp.get("content", "")
    elif tool == "Edit":
        content = inp.get("new_string", "")

    # Patterns for common API keys and secrets
    secret_patterns = [
        r'sk-proj-\w+',           # OpenAI project keys
        r'sk_(?:live|test)_\w+',  # Stripe keys
        r'pk_(?:live|test)_\w+',  # Stripe public keys
        r'rk_(?:live|test)_\w+',  # Stripe restricted keys
    ]

    for pattern in secret_patterns:
        if re.search(pattern, content):
            msg = "BLOCKING: Detected potential API key or secret in source code.\n"
            msg += "Secrets must come from process.env, not hardcoded.\n"
            msg += "See CLAUDE.md: 'Secrets come from the environment.'"
            print(msg, file=sys.stderr)
            return 2

    return 0

if __name__ == "__main__":
    sys.exit(main())

