        ev = json.load(sys.stdin)
    except Exception:
        return 0

    tool = ev.get("tool_name", "")
    if tool != "Edit":
        return 0

    inp = ev.get("tool_input") or {}
    file_path = inp.get("file_path", "")

    if not file_path.endswith(".py") or not os.path.exists(file_path):
        return 0

    try:
        result = subprocess.run(
            ["flake8", file_path, "--extend-ignore=E501"],
            capture_output=True,
            text=True,
            timeout=5
        )
        if result.stdout and result.returncode != 0:
            print("Flake8 issues found:", file=sys.stderr)
            print(result.stdout, file=sys.stderr)
            print("REQUIRED FOLLOW-UP: Fix these issues in the edited file.", file=sys.stderr)
    except (FileNotFoundError, subprocess.TimeoutExpired, Exception):
        pass

    return 0

if __name__ == "__main__":
    sys.exit(main())
